async function main() {
  const vendor = await db.vendor.findUnique({ where: { slug: VENDOR_SLUG } });
  if (!vendor) throw new Error(`Vendor "${VENDOR_SLUG}" not found — run prisma seed first.`);

  const exam = await db.exam.upsert({
    where: { slug: EXAM_SLUG },
    update: {
      title: 'AWS Certified Machine Learning Engineer Associate (Practice Exam 1)',
      description: 'AWS Certified Machine Learning Engineer Associate (MLA-C01) practice set covering ML lifecycle, SageMaker, data engineering for ML, model deployment, and MLOps on AWS. Sourced from a third-party practice exam PDF. Not real exam questions.',
      level: 'Associate',
      durationMinutes: 130,
      passingScore: 75,
      questionCount: 35,
      domains: DOMAINS,
      published: false
    },
    create: {
      vendorId: vendor.id,
      code: 'MLA-C01-P1',
      slug: EXAM_SLUG,
      title: 'AWS Certified Machine Learning Engineer Associate (Practice Exam 1)',
      description: 'AWS Certified Machine Learning Engineer Associate (MLA-C01) practice set covering ML lifecycle, SageMaker, data engineering for ML, model deployment, and MLOps on AWS. Sourced from a third-party practice exam PDF. Not real exam questions.',
      level: 'Associate',
      durationMinutes: 130,
      passingScore: 75,
      questionCount: 35,
      domains: DOMAINS,
      pricePractice: 2900,
      priceBundle: 17900,
      priceVoucher: 14900,
      published: false
    }
  });

  const alreadySeeded = await db.question.count({
    where: { examId: exam.id, generatedBy: TAG }
  });
  if (alreadySeeded > 0) {
    console.log(`Already have ${alreadySeeded} questions tagged "${TAG}" — skipping.`);
    return;
  }

  let i = 0;
  for (const q of QUESTIONS) {
    await db.question.create({
      data: {
        examId: exam.id,
        domain: q.domain,
        difficulty: 3,
        type: q.type,
        stem: q.stem,
        options: q.options,
        correct: q.correct,
        explanation: q.explanation,
        references: [REF],
        status: QStatus.PUBLISHED,
        generatedBy: TAG,
        isTeaser: i < 10
      }
    });
    i++;
  }

  const total = await db.question.count({ where: { examId: exam.id, status: QStatus.PUBLISHED } });
  console.log(`✓ ${EXAM_SLUG} — inserted ${QUESTIONS.length} questions (${total} total published)`);
}

main()
  .catch((e) => { console.error(e); process.exit(1); })
  .finally(() => db.$disconnect());
